"use client";

import { SignIn, useUser } from "@clerk/nextjs";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { ShieldCheck, Zap } from "lucide-react";

export default function AdminLoginPage() {
  const { user, isLoaded } = useUser();
  const router = useRouter();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (mounted && isLoaded && user) {
      router.push("/admin");
    }
  }, [mounted, isLoaded, user, router]);

  if (!mounted) return null;

  return (
    <main className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
      <motion.div 
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-sm"
      >
        <div className="flex flex-col items-center mb-8">
           <div className="size-10 bg-primary rounded-xl flex items-center justify-center shadow-lg shadow-primary/20 mb-4">
              <ShieldCheck className="text-white size-6" />
           </div>
           <h1 className="text-lg font-bold text-slate-900 tracking-tight uppercase">Orphosys Admin</h1>
           <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Founders Secure Access</p>
        </div>

        <div className="bg-white border border-slate-200 rounded-3xl p-2 shadow-sm">
          <div className="bg-slate-50 border border-slate-100/50 rounded-2xl overflow-hidden p-1">
            <SignIn 
              path="/admin/login"
              appearance={{
                elements: {
                  rootBox: "w-full",
                  card: "bg-transparent shadow-none border-none p-4",
                  headerTitle: "text-slate-900 text-sm font-bold",
                  headerSubtitle: "text-slate-400 text-[11px] font-bold uppercase tracking-wider",
                  socialButtonsBlockButton: "bg-white border border-slate-200 hover:bg-slate-50 transition-all text-xs font-bold rounded-xl",
                  formButtonPrimary: "bg-primary hover:opacity-90 transition-all text-xs font-bold py-3 rounded-xl",
                  formFieldLabel: "text-slate-500 text-[10px] font-bold uppercase tracking-widest",
                  formFieldInput: "bg-white border border-slate-200 focus:border-primary/30 transition-all rounded-xl text-xs py-3 px-4",
                  footerActionText: "text-slate-400 text-[11px] font-bold",
                  footerActionLink: "text-primary hover:underline",
                  dividerText: "text-slate-300 text-[10px] uppercase font-bold px-4",
                  dividerLine: "bg-slate-100",
                  identityPreviewText: "text-slate-900 font-bold",
                  identityPreviewEditButtonIcon: "text-primary"
                }
              }}
            />
          </div>
        </div>

        <div className="mt-8 flex items-center justify-center gap-6">
           <div className="flex items-center gap-2">
              <Zap className="size-3 text-primary" />
              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-none">V2.4 Secure</span>
           </div>
           <div className="h-3 w-px bg-slate-200"></div>
           <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-none">AES-256 Auth Node</p>
        </div>
      </motion.div>
    </main>
  );
}
